var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"할아버지. 그동안 잘 지내고 계셨나요?","JPN":"お爺さん。そちらはどうですか？","ENG":"Grandfather. How have you been doing?","TWN":"爺爺，這段時間你過得好嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"전 잘 지내고 있어요. 지금껏 있었던 일들을 편지에는 전부 담기 힘들 정도로요.","JPN":"私は充実した日々を送っています。今までのことを手紙に全部書くのが難しいくらいに。","ENG":"I'm doing well. It's difficult to write down everything that's happened so far.","TWN":"我過得很好，這段時間發生的事多到我無法全部寫在信裡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"무슨 일이 있었는지 간략하게 설명해드리자면… 그곳에서 빠져나온 뒤 전 성녀가 되었어요.","JPN":"何があったのかを短く説明すると……あそこから出て、私は聖女になりました。","ENG":"To summarize past events... I became the Saintess after getting out of there.","TWN":"我就簡單說一下…離開那裡後，我成為聖女。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"이렇게까지 바라진 않았지만, 전부 할아버지의 말대로 된 셈이네요.","JPN":"ここまで望んでいたわけではなかったけれど、全部お爺さんの言うとおりになったわけです。","ENG":"I didn't wish for anything to this extent, but I guess it's as you said.","TWN":"雖然這一切超出我的期待，但一切就如爺爺所說的那樣。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"지금 들어간 기사단에서는.","JPN":"今居る騎士団には。","ENG":"In the order of knights I belong to...","TWN":"現在我加入的騎士團裡，"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"본인 잘난 맛에 사는 능글맞은 황태자에.","JPN":"尊大で、図々しい皇太子に。","ENG":"There is the haughty crown prince who is awfully prideful.","TWN":"有個自命不凡的油腔滑調皇太子。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"융통성이라고는 없는 기사단장.","JPN":"まったく融通が利かない騎士団長。","ENG":"The uncompromising captain.","TWN":"還有一個一絲不苟的騎士團長。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그나마 있는 여자애는 무슨 생각인지 알 수 없을 정도로 엉뚱하고.","JPN":"たった一人の女の子は、何を考えているのか全然わからないくらいに突拍子もなくて。","ENG":"The only other girl who is so eccentric that I can never know what she's thinking.","TWN":"另一個女生，也搞不懂她在想什麼，行為舉止怪異。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고……","JPN":"それから……","ENG":"And...","TWN":"另外…"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"고생하셨습니다. 기사단 여러분들께 정말 많은 민폐를 끼쳤군요.","JPN":"お疲れさまでした。騎士団の皆さんには多大なご迷惑をおかけしました。","ENG":"Thank you. And we're sorry for causing you so much trouble.","TWN":"騎士團的各位辛苦了，真的給你們添了很多麻煩。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래. 확실히 살펴봤으니 이번에야말로 끝난 일이겠지.","JPN":"ああ。ちゃんと調べたから今度こそ解決したはずだ。","ENG":"Right. We have thoroughly inspected the area this time, so it should be over.","TWN":"沒事，我們都確實檢查過了，這次應該沒有漏掉的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"자네들도 그동안 고생 많았네.","JPN":"君たちも、ご苦労だった。","ENG":"Good work, all of you.","TWN":"你們也辛苦了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"헌데, 그….","JPN":"ところで、その……","ENG":"But, uh...","TWN":"不過，那個…"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"샬롯 님께서는 무언가 불편한 점이라도?","JPN":"シャーロット様は、どこか具合でも悪いのですか？","ENG":"Is there a problem, Miss Martinez?","TWN":"夏洛特小姐是有什麼不開心的事嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"문제없다. 이번에도 구원자에게 진 게 분할 뿐이야.","JPN":"問題ない。今度も救世主に負けたのが悔しいだけだ。","ENG":"Nothing. I am simply angry at the fact that I lost to the Savior once again.","TWN":"我沒事，只是這次又輸給救贖者大人，心裡很不甘而已。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"설마 성녀를 도우러 갔는데도 토벌 수에서 밀릴 줄이야.","JPN":"まさか聖女を助けに行ったのに、討伐数で負けるとは。","ENG":"I cannot believe he still killed more monsters even after going to help the Saintess.","TWN":"沒想到他跑去幫聖女，我竟然還會輸。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"한심하기 짝이 없지. 제국의 성녀라는 녀석이 고작 미물들에게 쩔쩔매다니 말이야.","JPN":"情けない。帝国の聖女ともあろう者が塵芥ごときに慌てふためくとは。","ENG":"How pathetic. A Saintess of the Empire, suffering from lowly pests.","TWN":"真是可笑至極，堂堂帝國的聖女，竟然被區區小怪物困住。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"자신이 구원 기사단이라는 자각은 있는 건가?","JPN":"自分が救世騎士団であるという自覚はあるのか？","ENG":"Do you realize that you belong to the Knights of Redemption?","TWN":"你還有身為救贖騎士團的自覺嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"전하. 루크레시아는 최선을 다했습니다.","JPN":"殿下。ルクレシアは本当に頑張りました。","ENG":"Your Highness. Lucrecia tried her best.","TWN":"殿下，露可蕾西亞已經盡力了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이번 한 번은 너그럽게 넘어가 주세요.","JPN":"今度は大目に見てやってください。","ENG":"I ask for your generosity and hope you excuse her this one time.","TWN":"這次就請殿下少說二句吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"의외로군, 평민. 네가 이런 대화에 끼어들다니 말이야.","JPN":"意外だな、平民。貴様がこのような会話に口を挟むとは。","ENG":"It is unlike you to contribute to the conversation like this, peasant.","TWN":"真是意外，平民，這種時候你竟然會插嘴。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"단 둘이 있을 때 무슨 일이라도 있었던 거냐?","JPN":"二人でいた時、何かあったのか？","ENG":"Did something happen while you two were alone?","TWN":"你們二個獨處時是有發生什麼事嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"…Pardon?","TWN":"……什麼？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아, 아무 일도 없었습니다.","JPN":"な、何もありませんでした。","ENG":"N-nothing happened.","TWN":"才，才沒有。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};